        };
    }

    /// True when this node is named (not punctuation/whitespace).
    pub fn is_named(self: *Node) bool {
    const _result = c.ts_pack_node_is_named(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// True when this is an error node.
    pub fn is_error(self: *Node) bool {
    const _result = c.ts_pack_node_is_error(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// True when this is a missing-token node.
    pub fn is_missing(self: *Node) bool {
    const _result = c.ts_pack_node_is_missing(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// True when this is an "extra" node (e.g. a comment).
    pub fn is_extra(self: *Node) bool {
    const _result = c.ts_pack_node_is_extra(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// True when this node or any descendant is an error.
    pub fn has_error(self: *Node) bool {
    const _result = c.ts_pack_node_has_error(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// Return this node's parent, if any.
    pub fn parent(self: *Node) ?Node {
    const _result = c.ts_pack_node_parent(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// Return the i-th child of this node, if any.
    pub fn child(self: *Node, index: u32) ?Node {
    const _result = c.ts_pack_node_child(@as(*c.TS_PACKNode, @ptrCast(self._handle)), index);
        return _result;
    }

    /// Total number of children (including unnamed).
    pub fn child_count(self: *Node) u64 {
    const _result = c.ts_pack_node_child_count(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// Return the i-th named child of this node, if any.
    pub fn named_child(self: *Node, index: u32) ?Node {
    const _result = c.ts_pack_node_named_child(@as(*c.TS_PACKNode, @ptrCast(self._handle)), index);
        return _result;
    }

    /// Number of named children of this node.
    pub fn named_child_count(self: *Node) u64 {
    const _result = c.ts_pack_node_named_child_count(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return _result;
    }

    /// Look up a child by its grammar-defined field name.
    pub fn child_by_field_name(self: *Node, name: []const u8) error{OutOfMemory}!?Node {
    const name_z = try std.heap.c_allocator.dupeZ(u8, name);
        defer std.heap.c_allocator.free(name_z);
        const _result = c.ts_pack_node_child_by_field_name(@as(*c.TS_PACKNode, @ptrCast(self._handle)), name_z);
        return _result;
    }

    /// Return the S-expression form of this node's subtree.
    pub fn to_sexp(self: *Node) error{OutOfMemory}![]u8 {
    const _result = c.ts_pack_node_to_sexp(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return blk: {
            const slice = std.mem.span(_result);
            const owned = try std.heap.c_allocator.dupe(u8, slice);
            c.ts_pack_free_string(_result);
            break :blk owned;
        };
    }

    /// Return a `TreeCursor` positioned at this node.
    pub fn walk(self: *Node) TreeCursor {
    const _result = c.ts_pack_node_walk(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
        return TreeCursor{ ._handle = _result.? };
    }

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *Node) void {
    c.ts_pack_node_free(@as(*c.TS_PACKNode, @ptrCast(self._handle)));
    }
};

/// A cursor for traversing a `Tree`.
pub const TreeCursor = struct {
    _handle: *anyopaque,

    /// Return the `Node` at the cursor's current position.
    pub fn node(self: *TreeCursor) Node {
    const _result = c.ts_pack_tree_cursor_node(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
        return Node{ ._handle = _result.? };
    }

    /// Move the cursor to the first child of the current node.
    /// Returns `true` if a child existed.
    pub fn goto_first_child(self: *TreeCursor) bool {
    const _result = c.ts_pack_tree_cursor_goto_first_child(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
        return _result;
    }

    /// Move the cursor to the parent of the current node.
    /// Returns `true` if a parent existed.
    pub fn goto_parent(self: *TreeCursor) bool {
    const _result = c.ts_pack_tree_cursor_goto_parent(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
        return _result;
    }

    /// Move the cursor to the next sibling of the current node.
    /// Returns `true` if a sibling existed.
    pub fn goto_next_sibling(self: *TreeCursor) bool {
    const _result = c.ts_pack_tree_cursor_goto_next_sibling(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
        return _result;
    }

    /// Return the field name for the current node, if any.
    pub fn field_name(self: *TreeCursor) ?[]u8 {
    const _result = c.ts_pack_tree_cursor_field_name(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
        return _result;
    }

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *TreeCursor) void {
    c.ts_pack_tree_cursor_free(@as(*c.TS_PACKTreeCursor, @ptrCast(self._handle)));
    }
};

/// Create a new registry populated with all statically compiled languages.
///
/// When the `dynamic-loading` feature is enabled, the registry also knows
/// about dynamically loadable grammars and will load them on demand.
pub fn new_language_registry() LanguageRegistry {
    const _handle = c.ts_pack_language_registry_new();
    if (_handle == null) return _first_error(anyerror);
    return .{ ._handle = @as(*c.TS_PACKLanguageRegistry, @ptrCast(_handle.?)) };
}

pub fn default_language_registry() LanguageRegistry {
    const _handle = c.ts_pack_language_registry_default();
    if (_handle == null) return _first_error(anyerror);
    return .{ ._handle = @as(*c.TS_PACKLanguageRegistry, @ptrCast(_handle.?)) };
}

/// Thread-safe registry of tree-sitter language parsers.
///
/// Manages both statically compiled and dynamically loaded language grammars.
/// Use `LanguageRegistry.new()` for the default registry, or access the
/// global instance via the module-level convenience functions
/// (`get_language`, `available_languages`, etc.).
pub const LanguageRegistry = struct {
    _handle: *anyopaque,

    /// Get a tree-sitter `Language` by name.
    ///
    /// Resolves aliases (e.g., `"shell"` -> `"bash"`, `"makefile"` -> `"make"`),
    /// then looks up the language in the static table. When the `dynamic-loading`
    /// feature is enabled, falls back to loading a shared library on demand.
    ///
    /// **Errors:**
    ///
    /// Returns `Error.LanguageNotFound` if the name (after alias resolution)
    /// does not match any known grammar.
    pub fn get_language(self: *LanguageRegistry, name: []const u8) (Error||error{OutOfMemory})!Language {
    const name_z = try std.heap.c_allocator.dupeZ(u8, name);
        defer std.heap.c_allocator.free(name_z);
        const _result = c.ts_pack_language_registry_get_language(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)), name_z);
        if (_result == null) {
            return _first_error(Error);
        }
        return Language{ ._handle = _result.? };
    }

    /// List all available language names, sorted and deduplicated.
    ///
    /// Includes statically compiled languages, dynamically loadable languages
    /// (if the `dynamic-loading` feature is enabled), and all configured aliases.
    pub fn available_languages(self: *LanguageRegistry) error{OutOfMemory}![]u8 {
    const _result = c.ts_pack_language_registry_available_languages(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)));
        return blk: {
            const slice = std.mem.span(_result);
            const owned = try std.heap.c_allocator.dupe(u8, slice);
            c.ts_pack_free_string(_result);
            break :blk owned;
        };
    }

    /// Check whether a parser is statically compiled into this build.
    ///
    /// Returns `true` only when the grammar was compiled in at build time
    /// (i.e. it appears in the `STATIC_LANGUAGES` table). This is independent
    /// of the extension-to-language mapping: `detect_language_from_extension`
    /// consults the static ext table for all 306 grammars regardless of which
    /// parsers are compiled in.
    ///
    /// Use this when you need to distinguish "we know the language name" from
    /// "we can actually parse files in that language right now".
    ///
    /// ```no_run
    /// use tree_sitter_language_pack::{detect_language_from_extension, LanguageRegistry};
    ///
    /// let registry = LanguageRegistry::new();
    /// // Extension detection uses the static table — independent of compiled parsers.
    /// let lang = detect_language_from_extension("feature"); // always returns Some("gherkin")
    /// // Parser availability depends on which grammars were compiled in.
    /// let can_parse = lang.map(|name| registry.has_parser(name)).unwrap_or(false);
    /// ```
    pub fn has_parser(self: *LanguageRegistry, name: []const u8) error{OutOfMemory}!bool {
    const name_z = try std.heap.c_allocator.dupeZ(u8, name);
        defer std.heap.c_allocator.free(name_z);
        const _result = c.ts_pack_language_registry_has_parser(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)), name_z);
        return _result;
    }

    /// Check whether a language is available by name or alias.
    ///
    /// Returns `true` if the language can be loaded, either from the static
    /// table or from a dynamic library on disk.
    pub fn has_language(self: *LanguageRegistry, name: []const u8) error{OutOfMemory}!bool {
    const name_z = try std.heap.c_allocator.dupeZ(u8, name);
        defer std.heap.c_allocator.free(name_z);
        const _result = c.ts_pack_language_registry_has_language(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)), name_z);
        return _result;
    }

    /// Return the total number of available languages (including aliases).
    pub fn language_count(self: *LanguageRegistry) u64 {
    const _result = c.ts_pack_language_registry_language_count(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)));
        return _result;
    }

    /// Parse source code and extract file intelligence based on config in a single pass.
    pub fn process(self: *LanguageRegistry, source: []const u8, config: []const u8) (Error||error{OutOfMemory})![]u8 {
    const source_z = try std.heap.c_allocator.dupeZ(u8, source);
        defer std.heap.c_allocator.free(source_z);
        const config_z = try std.heap.c_allocator.dupeZ(u8, config);
        defer std.heap.c_allocator.free(config_z);
        const config_handle = c.ts_pack_process_config_from_json(config_z.ptr);
        if (config_handle == null) return _first_error(Error);
        defer c.ts_pack_process_config_free(config_handle);
        const _result = c.ts_pack_language_registry_process(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)), source_z, config_handle);
        if (_result == null) {
            return _first_error(Error);
        }
        return blk: {
            const _json_ptr = c.ts_pack_process_result_to_json(_result);
            const _json_slice = std.mem.span(_json_ptr);
            const owned = try std.heap.c_allocator.dupe(u8, _json_slice);
            c.ts_pack_free_string(_json_ptr);
            c.ts_pack_process_result_free(_result);
            break :blk owned;
        };
    }

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *LanguageRegistry) void {
    c.ts_pack_language_registry_free(@as(*c.TS_PACKLanguageRegistry, @ptrCast(self._handle)));
    }
};

/// Create a new download manager for the given version.
pub fn new_download_manager(version: []const u8) error{OutOfMemory}!DownloadManager {
    const version_z = try std.heap.c_allocator.dupeZ(u8, version);
    defer std.heap.c_allocator.free(version_z);
    const _handle = c.ts_pack_download_manager_new(version_z.ptr);
    if (_handle == null) return _first_error(anyerror);
    return .{ ._handle = @as(*c.TS_PACKDownloadManager, @ptrCast(_handle.?)) };
}

/// Manages downloading and caching of pre-built parser shared libraries.
pub const DownloadManager = struct {
    _handle: *anyopaque,

    /// List languages that are already downloaded and cached.
    pub fn installed_languages(self: *DownloadManager) error{OutOfMemory}![]u8 {
    const _result = c.ts_pack_download_manager_installed_languages(@as(*c.TS_PACKDownloadManager, @ptrCast(self._handle)));
        return blk: {
            const slice = std.mem.span(_result);
            const owned = try std.heap.c_allocator.dupe(u8, slice);
            c.ts_pack_free_string(_result);
            break :blk owned;
        };
    }

    /// Download the platform bundle and extract every library file it contains.
    ///
    /// Unlike `Self.ensure_languages`, this does not check the manifest language list
    /// against archive contents — it simply extracts all `.so`/`.dylib`/`.dll` files
    /// from the bundle. Languages in the manifest that are missing from the archive
    /// are silently ignored rather than returning an error.
    ///
    /// Returns the number of library files extracted (including those already cached).
    pub fn download_all_best_effort(self: *DownloadManager) (Error||error{OutOfMemory})!u64 {
    const _result = c.ts_pack_download_manager_download_all_best_effort(@as(*c.TS_PACKDownloadManager, @ptrCast(self._handle)));
        if (_result == null) {
            return _first_error(Error);
        }
        return _result;
    }

    /// Remove all cached parser libraries.
    ///
    /// Acquires the cross-process lock so `clean_cache` cannot race a concurrent
    /// downloader (avoids Windows sharing-violation errors against an in-flight
    /// bundle write). The `.download.lock` file itself is **not** removed — it is
    /// permanent infrastructure; deleting it could allow a concurrent process that
    /// already opened the file to continue holding a stale lock handle while a new
    /// process opens a fresh inode, breaking the mutual-exclusion guarantee.
    pub fn clean_cache(self: *DownloadManager) (Error||error{OutOfMemory})!void {
    _ = c.ts_pack_download_manager_clean_cache(@as(*c.TS_PACKDownloadManager, @ptrCast(self._handle)));
        if (c.ts_pack_last_error_code() != 0) {
            return _error_with_message(Error);
        }
    }

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *DownloadManager) void {
    c.ts_pack_download_manager_free(@as(*c.TS_PACKDownloadManager, @ptrCast(self._handle)));
    }
};

pub const Language = struct {
    _handle: *anyopaque,

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *Language) void {
    c.ts_pack_language_free(@as(*c.TS_PACKLanguage, @ptrCast(self._handle)));
    }
};
